const cwd="/Users/zchee/go/src/github.com/zchee/spanner-manager";
const team="implement-approved-plan-omx-pl";
const cmd = `
set -euo pipefail
team=${team}
supersede_task() {
  local id="$1" worker="$2" result="$3"
  claim=$(omx team api claim-task --input "$(jq -nc --arg team "$team" --arg id "$id" --arg worker "$worker" '{team_name:$team,task_id:$id,worker:$worker}')" --json)
  echo "$claim"
  token=$(printf '%s' "$claim" | jq -r '.data.claim_token // .data.token // .claim_token // .token')
  omx team api transition-task-status --input "$(jq -nc --arg team "$team" --arg id "$id" --arg token "$token" --arg result "$result" '{team_name:$team,task_id:$id,from:"in_progress",to:"completed",claim_token:$token,result:$result}')" --json
}
supersede_task 2 worker-1 "Superseded by explicit leader-created core implementation task assigned to worker-2 after task split produced mismatched durable owner."
supersede_task 3 worker-1 "Superseded by explicit leader-created core implementation task assigned to worker-2; worker-3 claim conflict acknowledged."
supersede_task 4 worker-1 "Superseded by explicit leader-created support-matrix task assigned to worker-4 after malformed owner split."
supersede_task 7 worker-1 "Superseded by explicit leader-created core implementation task preserving data-safety defaults."
supersede_task 10 worker-4 "Superseded by explicit leader-created support-matrix task; commit discipline remains in worker instructions."

echo '--- create explicit tasks ---'
omx team api create-task --input "$(jq -nc --arg team "$team" '{team_name:$team,owner:"worker-2",requires_code_change:true,subject:"Implement core data-safe diff fixes from regression tests",description:"Sole production edit owner for diff/diff.go, diff/database.go, and any required sqlutil changes. First cherry-pick worker-1 test commit 01ab53898f62a14de1f591fe3be5f38afbd6e64b into your worktree, then make tests pass for data-preserving STRING/BYTES column widening, unsupported type-change fail-loud behavior, sequence safety, interleave/primary-key safety, literal-safe normalization, stable constraint identity, unchanged views, and unsupported modern DDL not silently ignored. Coordinate by not touching docs/support matrix owned by worker-4. Commit your lane changes."}')" --json
omx team api create-task --input "$(jq -nc --arg team "$team" '{team_name:$team,owner:"worker-4",requires_code_change:true,subject:"Add modern DDL support matrix and fail-loud documentation",description:"Own docs/support matrix only plus minimal tests if needed for documentation anchors. Do not edit diff/diff.go while worker-2 owns core production logic. Document parser support, diff support, unsupported/fail-loud gaps, live-Spanner validation gaps, and destructive-policy guardrails. Commit your lane changes."}')" --json
omx team api create-task --input "$(jq -nc --arg team "$team" '{team_name:$team,owner:"worker-5",requires_code_change:false,subject:"Final verification after leader integrates worker commits",description:"Wait for leader/inbox signal that worker implementation commits have been integrated into the leader branch, then run final verification: go test ./diff -count=1; go test ./sqlutil -count=1 if touched; go test ./... -count=1; go vet ./...; git diff --check. Report exact pass/fail evidence. Read-only unless fixing test harness is explicitly requested."}')" --json

printf '%s\\n' '--- list tasks ---'
omx team api list-tasks --input "$(jq -nc --arg team "$team" '{team_name:$team}')" --json | jq '.data.tasks[] | {id,owner,status,subject}'
`;
const out=await tools.shell_command({command: cmd, workdir: cwd, timeout_ms: 60000});
text(out);

