  token=$(jq -r '.claim.token' ".omx/state/team/$team/tasks/task-$id.json")
  omx team api transition-task-status --input "$(jq -nc --arg team "$team" --arg id "$id" --arg token "$token" --arg result "$result" '{team_name:$team,task_id:$id,from:"in_progress",to:"completed",claim_token:$token,result:$result}')" --json
}
complete_existing_claim 2 "Superseded by explicit leader-created task 12 assigned to worker-2 because initial task split produced mismatched durable owner."
complete_existing_claim 3 "Superseded by explicit leader-created task 12 assigned to worker-2 after worker-3 reported claim conflict; worker-2 is sole core production edit owner."
complete_existing_claim 4 "Superseded by explicit leader-created task 13 assigned to worker-4 because initial task split produced mismatched durable owner."

claim=$(omx team api claim-task --input "$(jq -nc --arg team "$team" '{team_name:$team,task_id:"11",worker:"worker-5"}')" --json)
echo "$claim"
token=$(printf '%s' "$claim" | jq -r '.data.claimToken // .data.claim_token // .claimToken // .claim_token')
omx team api transition-task-status --input "$(jq -nc --arg team "$team" --arg token "$token" '{team_name:$team,task_id:"11",from:"in_progress",to:"completed",claim_token:$token,result:"Superseded by explicit leader-created final verification task 14 after implementation commit integration."}')" --json

