omx team api list-tasks --input "$(jq -nc --arg team "$team" '{team_name:$team}')" --json | jq '.data.tasks[] | {id,owner,status,subject,claim}'
`;
const out=await tools.shell_command({command: cmd, workdir: cwd, timeout_ms: 60000});
text(out);

