const cwd="/Users/zchee/go/src/github.com/zchee/spanner-manager";
const team="implement-approved-plan-omx-pl";
const cmd=`
set -euo pipefail
team=${team}
omx team api write-worker-inbox --input "$(jq -nc --arg team "$team" '{team_name:$team,worker:"worker-2",content:"# Inbox update from leader\\n\\nClaim task 12 now. You are sole production edit owner for core diff implementation. First cherry-pick worker-1 commit 01ab53898f62a14de1f591fe3be5f38afbd6e64b, then implement the production logic needed to pass those tests. Do not edit docs/support matrix. Commit your lane changes before reporting completion."}')" --json
omx team api write-worker-inbox --input "$(jq -nc --arg team "$team" '{team_name:$team,worker:"worker-4",content:"# Inbox update from leader\\n\\nClaim task 13 now. Own support matrix/docs only. Do not edit diff/diff.go while worker-2 owns core production logic. Commit your lane changes before reporting completion."}')" --json
omx team api write-worker-inbox --input "$(jq -nc --arg team "$team" '{team_name:$team,worker:"worker-5",content:"# Inbox update from leader\\n\\nTask 14 is final verification, but wait until leader confirms worker commits are integrated into the leader branch. Stay ready; do not run final verification against stale worktree yet."}')" --json
omx team api write-worker-inbox --input "$(jq -nc --arg team "$team" '{team_name:$team,worker:"worker-3",content:"# Inbox update from leader\\n\\nYour earlier claim conflict is acknowledged and resolved by moving production implementation to worker-2. Stand by read-only; do not edit files unless leader creates a new task for you."}')" --json
printf '\\n--- resume ---\\n'
omx team resume "$team" || true
printf '\\n--- status ---\\n'
omx team status "$team" --json
`;
const out=await tools.shell_command({command: cmd, workdir: cwd, timeout_ms: 60000});
text(out);

