const cwd="/Users/zchee/go/src/github.com/zchee/spanner-manager";
const out=await tools.shell_command({command:"omx team api broadcast --help; printf '\\n--- mailbox list help ---\\n'; omx team api mailbox-list --help", workdir:cwd, timeout_ms:20000});
text(out);

const cwd="/Users/zchee/go/src/github.com/zchee/spanner-manager";
const team="implement-approved-plan-omx-pl";
const cmd=`
set -euo pipefail
team=${team}
for pair in "worker-2:Task 12 is ready; read inbox, claim task 12, cherry-pick worker-1 test commit, implement, commit, report." "worker-4:Task 13 is ready; read inbox, claim task 13, docs/support matrix only, commit, report." "worker-5:Task 14 is pending; read inbox and wait for leader integration signal before final verification." "worker-3:Stand by read-only; claim conflict resolved; do not edit unless assigned."; do
  worker="\${pair%%:*}"
  body="\${pair#*:}"
  omx team api send-message --input "$(jq -nc --arg team "$team" --arg worker "$worker" --arg body "$body" '{team_name:$team,from_worker:"leader-fixed",to_worker:$worker,body:$body}')" --json
done
printf '\\n--- mailboxes worker2/4/5 ---\\n'
for w in worker-2 worker-4 worker-5; do echo "### $w"; omx team api mailbox-list --input "$(jq -nc --arg team "$team" --arg w "$w" '{team_name:$team,worker:$w}')" --json | jq '.data.messages[-5:]'; done
printf '\\n--- status ---\\n'
omx team status "$team" --json
`;
const out=await tools.shell_command({command:cmd, workdir:cwd, timeout_ms:60000});
text(out);

